import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Dynamically allocating memory for buffer based on user input length
        char[] buffer = new char[userInput.length()];
        userInput.getChars(0, userInput.length(), buffer, 0);

        // Displaying the content of the buffer
        System.out.println("Buffer content: " + new String(buffer));

        // Now, there is no risk of Buffer Overflow as buffer size is dynamically determined
    }
}

